Вопрос: стоит ли сразу добавлять `useSubmitHandler`, если пока достаточно стандартного handleSubmit, или можно интегрировать позже без изменения API?

Отличное решение. Оставлю `useSubmitHandler` на будущее, когда появятся дополнительные требования к обработке submit.

Создал базовую структуру:

```typescript
// src/hooks/forms/useFormController.ts
import { UseFormReturn, FieldErrors } from 'react-hook-form';
import { z } from 'zod';
import { useFormBase } from './useFormBase';
import { useValidation } from './useValidation';

type UseFormControllerOptions<T> = {
  schema: z.ZodType<T>;
  defaultValues?: Partial<T>;
  mode?: 'onChange' | 'onBlur' | 'onSubmit' | 'all';
  onValid: (data: T) => Promise<void> | void;
  onInvalid?: (errors: FieldErrors<T>) => void;
};

type UseFormControllerReturn<T> = {
  methods: UseFormReturn<T>;
  submit: (e?: React.BaseSyntheticEvent) => Promise<void>;
  formState: UseFormReturn<T>['formState'];
};

export function useFormController<T>(options: UseFormControllerOptions<T>): UseFormControllerReturn<T> {
  const { resolver } = useValidation<T>({
    schema: options.schema
  });

  const methods = useFormBase<T>({
    resolver,
    defaultValues: options.defaultValues,
    mode: options.mode,
  });

  const submit = methods.handleSubmit(
    async (data) => {
      await options.onValid(data);
    },
    (errors) => options.onInvalid?.(errors)
  );

  return {
    methods,
    submit,
    formState: methods.formState,
  };
}
```

```typescript
