## Вариант 1 (самый универсальный): `useInput` возвращает `registerProps` + `error`

Под ваш текущий подход (Input как компонент, который принимает `error` как строку/ReactNode) удобно так:

```ts
import { UseFormReturn, FieldPath } from "react-hook-form";

type UseInputReturn<T> = {
  registerProps: ReturnType<UseFormReturn<T>["register"]>;
  error?: string;
};

export function useInput<T>(params: {
  methods: UseFormReturn<T>;
  name: FieldPath<T>;
}): UseInputReturn<T> {
  const { methods, name } = params;

  const error = methods.formState.errors[name];
  // ZodResolver обычно кладёт message в `error.message`, но тип RHF общий.
  const errorMessage =
    typeof (error as any)?.message === "string" ? (error as any).message : undefined;

  return {
    registerProps: methods.register(name),
    error: errorMessage,
  };
}
```

Использование:
```tsx
const email = useInput<LoginFormValues>({ methods, name: "email" });

<Input {...email.registerProps} error={email.error} />
```

### Плюсы
- UI остаётся вашим: `Input` решает как отображать `error`.
- минимальная магия и легко тестировать.
- тип `name` безопасный (`FieldPath<T>`).

---

## Вариант 2 (если вы хотите единый API для helperText/aria): вернуть `fieldProps` + `meta`

```ts
type UseFieldMeta = {
  error?: string;
  invalid: boolean;
};

export function useInput<T>(params: {
  methods: UseFormReturn<T>;
  name: FieldPath<T>;
}) {
  const { methods, name } = params;

  const errorObj = methods.formState.errors[name];
  const errorMessage =
    typeof (errorObj as any)?.message === "string" ? (errorObj as any).message : undefined;

  const invalid = Boolean(errorMessage);

  return {
    fieldProps: methods.register(name),
    meta: { error: errorMessage, invalid },
  };
}
```

Использование:
```tsx
const email = useInput<LoginFormValues>({ methods, name: "email" });

<Input
  {...email.fieldProps}
  error={email.meta.error}
  aria-invalid={email.meta.invalid}
/>
```

